  function parseData(text) {
    // Phân tích dữ liệu chính
    const data = { home: {}, chars: [], reviews: [] };
    // Giữ nguyên regex tiếng Trung để khớp với dữ liệu đầu vào (Input Data)
    const homeBlock = text.match(/\[基本信息\]([\s\S]*?)(?=\[|$)/);
    if (homeBlock) {
      homeBlock[1].trim().split('\n').forEach(line => {
        const parts = line.split(':');
        if (parts.length >= 2) data.home[parts[0].trim()] = parts.slice(1).join(':').trim();
      });
    }
    // Phân tích bình luận
    const reviewBlock = text.match(/\[游客点评\]([\s\S]*?)\[\/游客点评\]/);
    if (reviewBlock) {
      reviewBlock[1].trim().split('\n').forEach(line => {
          if (!line.includes('//') && line.trim() !== '') {
              data.reviews.push(line.replace(/^评论\d+:\s*/, ''));
          }
      });
    }
    // Phân tích nhân vật
    const charRegex = /\[角色_(.*?)\]([\s\S]*?)\[\/角色_\1\]/g;
    let match;
    while ((match = charRegex.exec(text)) !== null) {
      const charName = match[1];
      const content = match[2];
      const charInfo = {};
      content.split('\n').forEach(line => {
        const parts = line.split(':');
        if (parts.length >= 2) charInfo[parts[0].trim()] = parts.slice(1).join(':').trim();
      });
      data.chars.push({ name: charName, info: charInfo });
    }
    return data;
  }

